#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long A,B,C,D,E; scanf("%lld %lld %lld %lld %lld", &A,&B,&C,&D,&E);
        int ok = (A+B<=D && C<=E) || (A+C<=D && B<=E) || (B+C<=D && A<=E);
        puts(ok?"YES":"NO");
    }
    return 0;
}

